import java.util.List;
import java.util.stream.Collectors;

import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.TripleRef;
import org.eclipse.rdf4j.query.algebra.evaluation.impl.EvaluationStatistics;
import org.eclipse.rdf4j.sail.base.SailStore;

final class MultiRepoEvaluationStatistics extends EvaluationStatistics {

	private final List<EvaluationStatistics> delegates;

	MultiRepoEvaluationStatistics(List<SailStore> stores) {
		this.delegates = stores.stream()
				.map(SailStore::getEvaluationStatistics)
				.collect(Collectors.toList());
	}

	@Override
	protected CardinalityCalculator createCardinalityCalculator() {
		return new MultiRepoCardinalityCalculator();
	}

	@Override
	public boolean supportsJoinEstimation() {
		return delegates.stream().anyMatch(EvaluationStatistics::supportsJoinEstimation);
	}

	private final class MultiRepoCardinalityCalculator extends CardinalityCalculator {

		@Override
		protected double getCardinality(StatementPattern sp) {
			if (delegates.isEmpty()) {
				return super.getCardinality(sp);
			}
			return delegates.stream()
					.mapToDouble(delegate -> delegate.getCardinality(sp.clone()))
					.sum();
		}

		@Override
		protected double getCardinality(TripleRef tripleRef) {
			if (delegates.isEmpty()) {
				return super.getCardinality(tripleRef);
			}
			return delegates.stream()
					.mapToDouble(delegate -> delegate.getCardinality(tripleRef.clone()))
					.sum();
		}
	}
}
